module mux_8to1 (A, B, C, D, E, F, G, H, desel, Y);
input A;
input B;
input C;
input D;
input E;
input F;
input G;
input H;
input [2:0] desel;
output Y;

assign Y = (desel == 3'b000) ? A :
           (desel == 3'b001) ? B :
           (desel == 3'b010) ? C :
           (desel == 3'b011) ? D :
           (desel == 3'b100) ? E :
           (desel == 3'b101) ? F :
           (desel == 3'b110) ? G : H;

endmodule
